#include <iostream>
#include <iomanip>
#include <string>

class Employee {
public:
    std::string name;
    double salary;
    Employee(std::string n, double s) : name(n), salary(s) {}
    void printName() {
        std::cout << "Name: " << name << "\n";
    }
};

class Manager : public Employee {
public:
    int teamSize;
    Manager(std::string n, double s, int ts) : Employee(n, s), teamSize(ts) {}
    void printSummary() {
        printName();
        std::cout << std::fixed << std::setprecision(2);
        std::cout << "Salary: " << salary << "\n";
        std::cout << "Team: " << teamSize << "\n";
    }
};

int main() {
    std::string name;
    double salary;
    int ts;
    std::cin >> name >> salary >> ts;
    Manager m(name, salary, ts);
    m.printSummary();
    return 0;
}
